define float @fdiv_select_when_divisor_is_one(float %x) {
  %one.is.one = fcmp oeq float 1.000000e+00, 1.000000e+00
  %divided.x = fdiv nnan ninf float %x, 1.000000e+00
  %result = select nnan i1 %one.is.one, float %x, float %divided.x
  ret float %result
}

